n23: 			serverId = worker2.PrivateId
		}
n24: 		sess := session.TestDefaultSession(t, conn, wrapper, iamRepo, session.WithServerId(serverId), session.WithDbOpts(db.WithSkipVetForWrite(true)))
n25: 		sess, _, err = sessionRepo.ActivateSession(ctx, sess.GetPublicId(), sess.Version, serverId, "worker", []byte("foo"))
n26: 		require.NoError(err)
n27: 		c, cs, _, err := session.AuthorizeConnection(ctx, sessionRepo, connectionRepo, sess.GetPublicId(), serverId)
n28: 		require.NoError(err)
n29: 		require.Len(cs, 1)
n30: 		require.Equal(session.StatusAuthorized, cs[0].Status)
n31: 		connIds = append(connIds, c.GetPublicId())
n32: 		if i%2 == 0 {
n33: 			connIdsByWorker[worker2.PrivateId] = append(connIdsByWorker[worker2.PrivateId], c.GetPublicId())
		} else {
n34: 			connIdsByWorker[worker1.PrivateId] = append(connIdsByWorker[worker1.PrivateId], c.GetPublicId())
		}
	}

