n35: 	for i, connId := range connIds {
n36: 		if i%2 == 0 {
n37: 			_, cs, err := connectionRepo.ConnectConnection(ctx, session.ConnectWith{
				ConnectionId:       connId,
				ClientTcpAddress:   "127.0.0.1",
				ClientTcpPort:      22,
				EndpointTcpAddress: "127.0.0.1",
				EndpointTcpPort:    22,
				UserClientIp:       "127.0.0.1",
			})
n38: 			require.NoError(err)
n39: 			require.Len(cs, 2)
n40: 			var foundAuthorized, foundConnected bool
n41: 			for _, status := range cs {
n42: 				if status.Status == session.StatusAuthorized {
n43: 					foundAuthorized = true
				}
n44: 				if status.Status == session.StatusConnected {
n45: 					foundConnected = true
				}
			}
n46: 			require.True(foundAuthorized)
n47: 			require.True(foundConnected)
		}
	}

	// Create the job.
n48: 	job, err := newSessionConnectionCleanupJob(
		func() (*session.ConnectionRepository, error) { return connectionRepo, nil },
		session.DeadWorkerConnCloseMinGrace,
	)
n49: 	job.gracePeriod = gracePeriod // by-pass factory assert so we dont have to wait so long
n50: 	require.NoError(err)

	// sleep the status grace period.
n51: 	time.Sleep(gracePeriod)

	// Push an upsert to the first worker so that its status has been
	// updated.
n52: 	_, rowsUpdated, err := serversRepo.UpsertServer(ctx, worker1, []servers.Option{}...)
n53: 	require.NoError(err)
n54: 	require.Equal(1, rowsUpdated)

	// Run the job.
n55: 	require.NoError(job.Run(ctx))

	// Assert connection state on both workers.
n56: 	assertConnections := func(workerId string, closed bool) {
		connIds, ok := connIdsByWorker[workerId]
		require.True(ok)
		require.Len(connIds, 6)
		for _, connId := range connIds {
			_, states, err := connectionRepo.LookupConnection(ctx, connId, nil)
			require.NoError(err)
			var foundClosed bool
			for _, state := range states {
